/**
 * Rule Compiler
 *
 * Compiles configuration rules into optimized RegExp patterns for performance.
 * Extracted from ClassificationEngine to follow Single Responsibility Principle.
 */

import { CategoryConfiguration } from '../types/category-configuration';
import { CompiledRule } from '../types/api-types';

/**
 * RuleCompiler - Compiles configuration rules for runtime optimization
 *
 * Converts declarative rule patterns (containsAny, regexAny) into compiled
 * RegExp patterns for fast matching during classification.
 */
export class RuleCompiler {
  /**
   * Compile configuration rules into optimized patterns
   *
   * @param config - Category configuration with rule definitions
   * @returns Array of compiled rules with RegExp patterns
   */
  compileRules(config: CategoryConfiguration): CompiledRule[] {
    const rules: CompiledRule[] = [];

    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
        if (subtype.ruleBasedClassification) {
          for (const [tier, ruleList] of Object.entries(subtype.ruleBasedClassification)) {
            if (ruleList) {
              for (let ruleIndex = 0; ruleIndex < ruleList.length; ruleIndex++) {
                const rule = ruleList[ruleIndex];
                try {
                  const pattern = this.compilePattern(rule.operation, rule.values || []);
                  if (pattern) {
                    rules.push({
                      id: `${categoryName}.${subtypeName}.${tier}.${ruleIndex}`,
                      category: categoryName,
                      subtype: subtypeName,
                      pattern,
                      weight: rule.weight,
                      tier: tier as 'high' | 'medium' | 'low',
                    });
                  }
                } catch (error) {
                  // Skip invalid regex patterns
                  console.warn(
                    `Failed to compile rule for ${categoryName}.${subtypeName}.${tier}[${ruleIndex}]:`,
                    error
                  );
                }
              }
            }
          }
        }
      }
    }

    return rules;
  }

  /**
   * Compile a single pattern based on operation type
   *
   * @param operation - Rule operation (containsAny, regexAny, startsWith, endsWith)
   * @param values - Array of pattern values
   * @returns Compiled RegExp or null if operation not supported
   */
  private compilePattern(operation: string, values: string[]): RegExp | null {
    if (values.length === 0) {
      return null;
    }

    switch (operation) {
      case 'containsAny':
        // Escape special regex characters and join with OR
        return new RegExp(values.map((v) => this.escapeRegex(v)).join('|'), 'i');

      case 'startsWith':
        // Anchor at start and escape special characters
        return new RegExp('^(' + values.map((v) => this.escapeRegex(v)).join('|') + ')', 'i');

      case 'endsWith':
        // Anchor at end and escape special characters
        return new RegExp('(' + values.map((v) => this.escapeRegex(v)).join('|') + ')$', 'i');

      case 'regexAny':
        // Join raw regex patterns (assumes they're already valid)
        return new RegExp(values.join('|'), 'i');

      default:
        // Unsupported operation
        return null;
    }
  }

  /**
   * Escape special regex characters for literal matching
   *
   * @param str - String to escape
   * @returns Escaped string safe for use in RegExp
   */
  private escapeRegex(str: string): string {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }
}

// Default compiler instance
export const ruleCompiler = new RuleCompiler();

/**
 * API Adapters
 *
 * Type conversion utilities between API types and internal types.
 * Handles the impedance mismatch between REST API interfaces and
 * internal classification engine data structures.
 */

import { EmailContent, BatchClassificationResult } from '../types/api-types';
import { EmailMessage } from '../types/email-message';
import { ClassificationResult } from '../types/classification-result';

/**
 * Convert API EmailContent to internal EmailMessage format
 *
 * Maps the simplified REST API email format to the complete internal
 * EmailMessage structure used by the classification pipeline.
 *
 * @param email - Email from REST API request
 * @returns EmailMessage for classification pipeline
 */
export function convertEmailContentToMessage(email: EmailContent): EmailMessage {
  return {
    id: email.id,
    threadId: email.threadId,
    subject: email.subject || '',
    from: email.from,
    to: email.to || [],
    cc: email.cc,
    bcc: email.bcc,
    date: email.date,
    headers: email.headers || [],
    bodyPlain: email.bodyPlain,
    bodyHtml: email.bodyHtml,
    snippet: email.snippet,
    historyId: email.historyId,
    sizeEstimate: email.sizeEstimate,
    // Gmail API specific fields with defaults
    internalDate: email.date.getTime().toString(),
    labelIds: [],
    raw: '',
  };
}

/**
 * Convert internal ClassificationResult to API BatchClassificationResult
 *
 * Maps the internal classification result to the API response format
 * with flattened properties for easier client access.
 *
 * @param result - Internal classification result
 * @returns Batch classification result for API response
 */
export function convertClassificationResultToApi(result: ClassificationResult): BatchClassificationResult {
  return {
    emailId: result.emailId,
    classification: result,
    explainabilityTrace: result.explainabilityTrace,
    processingDurationMs: result.processingDurationMs,
    success: true,
    // Flattened properties for easier access
    primaryCategory: result.primaryCategory,
    confidence: result.confidence,
    scoreBreakdown: result.scoreBreakdown,
    attributeContext: result.attributeContext,
  };
}

/**
 * Create error result for batch processing
 *
 * Creates a standardized error result when email classification fails.
 *
 * @param emailId - ID of the email that failed
 * @param error - Error that occurred
 * @param processingDurationMs - Time spent before failure
 * @returns Batch classification result representing the error
 */
export function createErrorResult(
  emailId: string,
  error: Error,
  processingDurationMs: number
): BatchClassificationResult {
  return {
    emailId,
    classification: {} as ClassificationResult,
    processingDurationMs,
    success: false,
    error: error.message,
    // Default values for error state
    primaryCategory: 'error',
    confidence: 0,
    scoreBreakdown: {
      categoryScores: {},
      stageContributions: {},
    },
    attributeContext: {
      urgency: 'low',
      domains: [],
      structuralPatterns: [],
      temporalSignals: [],
    },
  };
}

