   424→            });
   425→          }
   426→        }
   427→      }
   428→    }
   429→
   430→    // Check for orphaned attributes (defined but not used)
   431→    const usedAttributes = new Set<string>();
   432→    for (const [categoryName, categoryConfig] of Object.entries(config.processingConfig.attributeRelevance)) {
   433→      if (categoryName === '_roles_legend') continue;
