   576→        });
   577→      }
   578→    }
   579→
   580→    // Validate performance settings
   581→    if (config.performanceTuning) {
   582→      const perf = config.performanceTuning;
   583→      if (perf.maxParallelEmails && perf.emailBatchSize) {
   584→        if (perf.maxParallelEmails > perf.emailBatchSize) {
   585→          warnings.push({
   586→            code: 'INEFFICIENT_PARALLEL_SETTINGS',
   587→            message: 'maxParallelEmails exceeds emailBatchSize',
   588→            path: 'performanceTuning',
