   618→  private async validateCrossConfigurationReferences(
   619→    categoryConfig: CategoryConfiguration,
   620→    domainSources: Record<string, string[]>
   621→  ): Promise<ValidationError[]> {
   622→    const errors: ValidationError[] = [];
   623→
   624→    // Validate domain references
   625→    const availableDomainGroups = new Set(Object.keys(domainSources));
   626→
   627→    for (const [categoryName, signals] of Object.entries(categoryConfig.processingConfig.categorySignals)) {
   628→      if (signals.hardAssertions?.fromDomainsRef) {
   629→        const groupName = signals.hardAssertions.fromDomainsRef.sourceGroup;
   630→        if (!availableDomainGroups.has(groupName)) {
   631→          errors.push({
   632→            code: 'INVALID_DOMAIN_GROUP_REFERENCE',
   633→            message: `Category "${categoryName}" references undefined domain group: "${groupName}"`,
   634→            path: `categorySignals.${categoryName}.hardAssertions.fromDomainsRef.sourceGroup`,
   635→            severity: 'error',
   636→            category: 'reference',
   637→            suggestion: `Define domain group "${groupName}" in domain sources or update the reference`,
   638→          });
   639→        }
   640→      }
   641→    }
   642→
   643→    return errors;
