   646→  private countRules(config: CategoryConfiguration): number {
   647→    let count = 0;
   648→    for (const category of Object.values(config.processingConfig.topLevelCategories)) {
   649→      for (const subtype of Object.values(category.subtypes)) {
   650→        if (subtype.ruleBasedClassification) {
   651→          for (const rules of Object.values(subtype.ruleBasedClassification)) {
   652→            if (rules) {
   653→              count += rules.length;
   654→            }
   655→          }
   656→        }
   657→      }
   658→    }
   659→    return count;
   660→  }
   661→
   662→  private isDangerousRegex(pattern: string): boolean {
   663→    // Basic check for potentially dangerous regex patterns
   664→    const dangerousPatterns = [
   665→      /\(.*\+.*\).*\+/, // Nested quantifiers
   666→      /\(.*\*.*\).*\*/, // Nested quantifiers
   667→      /\([^)]*\+[^)]*\)\+/, // Nested quantifiers
   668→      /\([^)]*\*[^)]*\)\*/, // Nested quantifiers
   669→    ];
   670→
   671→    return dangerousPatterns.some((dangerous) => dangerous.test(pattern));
   672→  }
