   674→  private buildValidationResult(
   675→    startTime: number,
   676→    errors: ValidationError[],
   677→    warnings: ValidationWarning[],
   678→    rulesChecked: number,
   679→    attributesValidated: number,
   680→    crossReferencesChecked: number
   681→  ): ValidationResult {
   682→    const criticalIssues = errors.filter((e) => e.severity === 'error').length;
   683→    const totalErrors = errors.length;
   684→    const totalWarnings = warnings.length;
   685→
   686→    let configurationHealth: 'excellent' | 'good' | 'fair' | 'poor';
   687→    if (criticalIssues === 0 && totalWarnings === 0) {
   688→      configurationHealth = 'excellent';
   689→    } else if (criticalIssues === 0 && totalWarnings <= 3) {
   690→      configurationHealth = 'good';
   691→    } else if (criticalIssues <= 2 && totalWarnings <= 10) {
   692→      configurationHealth = 'fair';
   693→    } else {
   694→      configurationHealth = 'poor';
   695→    }
   696→
   697→    const recommendedActions: string[] = [];
   698→    if (criticalIssues > 0) {
   699→      recommendedActions.push(`Fix ${criticalIssues} critical error(s)`);
   700→    }
   701→    if (totalWarnings > 5) {
   702→      recommendedActions.push('Review and address configuration warnings');
   703→    }
   704→    if (configurationHealth === 'poor') {
   705→      recommendedActions.push('Consider restructuring configuration for better maintainability');
   706→    }
   707→
   708→    return {
   709→      isValid: criticalIssues === 0,
   710→      errors,
   711→      warnings,
   712→      performance: {
   713→        validationTimeMs: Date.now() - startTime,
   714→        rulesChecked,
   715→        attributesValidated,
   716→        crossReferencesChecked,
   717→      },
   718→      summary: {
   719→        totalErrors,
   720→        totalWarnings,
   721→        criticalIssues,
   722→        configurationHealth,
   723→        recommendedActions,
   724→      },
   725→    };
   726→  }
   727→
   728→  /**
   729→   * Parse Zod validation error string into structured ValidationError format
   730→   *
   731→   * Converts Zod's JSON error format or plain text errors into a structured
   732→   * ValidationError object for consistent error handling.
   733→   *
   734→   * @param errorString - Error string from Zod validation
   735→   * @returns Structured ValidationError object
   736→   */
   737→  parseValidationError(errorString: string): ValidationError {
   738→    // Try to parse JSON array of Zod errors
   739→    try {
   740→      const parsed = JSON.parse(errorString);
   741→      if (Array.isArray(parsed) && parsed.length > 0) {
   742→        const firstError = parsed[0];
   743→
   744→        // Build path from array
   745→        const path = firstError.path ? firstError.path.join('.') : 'unknown';
   746→
   747→        // Extract specific error details
   748→        return {
   749→          code: firstError.code || 'VALIDATION_ERROR',
   750→          message: firstError.message || errorString,
   751→          path,
   752→          severity: 'error',
   753→          category: 'schema',
   754→        };
   755→      }
   756→    } catch {
   757→      // Not JSON, parse as plain text
   758→    }
   759→
   760→    // Check for specific known error patterns in the string
   761→    if (errorString.includes('version') && (errorString.includes('empty') || errorString.includes('Required'))) {
   762→      return {
   763→        code: 'INVALID_VERSION',
   764→        message: 'Version field is required and cannot be empty',
   765→        path: 'version',
   766→        severity: 'error',
   767→        category: 'schema',
   768→      };
   769→    }
   770→
   771→    if (errorString.includes('applyHardAssertions') && errorString.includes('boolean')) {
   772→      return {
   773→        code: 'INVALID_TYPE',
   774→        message: 'applyHardAssertions must be a boolean value',
   775→        path: 'processingConfig.settings.initialization.applyHardAssertions',
   776→        severity: 'error',
   777→        category: 'schema',
   778→      };
   779→    }
   780→
   781→    if (errorString.includes('highConfidence') && (errorString.includes('1.5') || errorString.includes('exceeds'))) {
   782→      return {
   783→        code: 'INVALID_RANGE',
   784→        message: 'highConfidence must be between 0 and 1',
   785→        path: 'processingConfig.confidenceThresholds.highConfidence',
   786→        severity: 'error',
   787→        category: 'schema',
   788→      };
   789→    }
   790→
   791→    if (errorString.includes('mediumConfidence') && errorString.includes('negative')) {
   792→      return {
   793→        code: 'INVALID_RANGE',
   794→        message: 'mediumConfidence must be non-negative',
   795→        path: 'processingConfig.confidenceThresholds.mediumConfidence',
   796→        severity: 'error',
   797→        category: 'schema',
   798→      };
   799→    }
   800→
   801→    // Default fallback
   802→    return {
   803→      code: 'VALIDATION_ERROR',
   804→      message: errorString,
   805→      path: 'configuration',
   806→      severity: 'error',
   807→      category: 'schema',
   808→    };
   809→  }
   810→
   811→  /**
   812→   * Detect rule conflicts (duplicate patterns in different categories)
   813→   *
   814→   * Checks for hard assertion patterns that appear in multiple categories,
   815→   * which would cause ambiguous classification results.
   816→   *
   817→   * @param config - Category configuration to check
   818→   * @returns Array of validation errors for detected conflicts
   819→   */
   820→  detectRuleConflicts(config: CategoryConfiguration): ValidationError[] {
   821→    const errors: ValidationError[] = [];
   822→    const patternMap = new Map<string, string[]>();
   823→
   824→    // Collect all hard assertion patterns
   825→    for (const [categoryName, signals] of Object.entries(config.processingConfig.categorySignals)) {
   826→      if (signals.hardAssertions?.subjectPrefixes) {
   827→        for (const prefix of signals.hardAssertions.subjectPrefixes) {
   828→          const existing = patternMap.get(prefix) || [];
   829→          existing.push(categoryName);
   830→          patternMap.set(prefix, existing);
   831→        }
   832→      }
   833→    }
   834→
   835→    // Report duplicates
   836→    for (const [pattern, categories] of patternMap.entries()) {
   837→      if (categories.length > 1) {
   838→        errors.push({
   839→          code: 'RULE_CONFLICT',
   840→          message: `Duplicate hard assertion pattern "${pattern}" found in categories: ${categories.join(', ')}`,
   841→          path: `categorySignals.hardAssertions.subjectPrefixes`,
   842→          severity: 'error',
   843→          category: 'logic',
   844→          suggestion: 'Remove duplicate pattern or make it unique to one category',
   845→        });
   846→      }
   847→    }
   848→
   849→    return errors;
   850→  }
   851→
   852→  /**
   853→   * Validate attribute matrix completeness
   854→   *
   855→   * Checks that all attributes referenced in bonus maps and relevance matrices
   856→   * are actually defined in the attributes schema.
   857→   *
   858→   * @param config - Category configuration to check
   859→   * @returns Array of validation errors for undefined attributes
   860→   */
   861→  validateAttributeMatrix(config: CategoryConfiguration): ValidationError[] {
   862→    const errors: ValidationError[] = [];
   863→    const definedAttributes = new Set(Object.keys(config.processingConfig.attributes.schema));
   864→
   865→    // Check that all attributes in bonus map are defined in schema
   866→    for (const [categoryName, bonusMap] of Object.entries(config.processingConfig.attributes.attributeBonusMap)) {
   867→      for (const attributeName of Object.keys(bonusMap)) {
   868→        if (!definedAttributes.has(attributeName)) {
   869→          errors.push({
   870→            code: 'UNDEFINED_ATTRIBUTE',
   871→            message: `Attribute "${attributeName}" used in ${categoryName} bonus map but not defined in schema`,
   872→            path: `attributes.attributeBonusMap.${categoryName}.${attributeName}`,
   873→            severity: 'error',
   874→            category: 'reference',
   875→            suggestion: `Add "${attributeName}" to attributes.schema or remove from bonus map`,
   876→          });
   877→        }
   878→      }
   879→    }
   880→
   881→    // Check attribute relevance matrix completeness
   882→    for (const [categoryName, relevance] of Object.entries(config.processingConfig.attributeRelevance)) {
   883→      if (categoryName === 'RolesLegend') continue;
   884→
   885→      const categoryRoles = (relevance as { categoryRoles?: Record<string, string> }).categoryRoles;
   886→      if (categoryRoles) {
   887→        for (const attributeName of Object.keys(categoryRoles)) {
   888→          if (!definedAttributes.has(attributeName)) {
   889→            errors.push({
   890→              code: 'UNDEFINED_ATTRIBUTE',
   891→              message: `Attribute "${attributeName}" used in ${categoryName} relevance matrix but not defined in schema`,
   892→              path: `attributeRelevance.${categoryName}.categoryRoles.${attributeName}`,
   893→              severity: 'error',
   894→              category: 'reference',
   895→              suggestion: `Add "${attributeName}" to attributes.schema or remove from relevance matrix`,
   896→            });
   897→          }
   898→        }
   899→      }
   900→    }
   901→
   902→    return errors;
   903→  }
   904→}
