import { z } from 'zod';

/**
 * Zod schema for ProcessingConfig validation
 * Includes all tuning parameters per ${repoRoot}/docs/SCORING_LOGIC.md throughout
 */

// Base validation schemas
const PositiveNumberSchema = z.number().min(0);
const ProbabilitySchema = z.number().min(0).max(1);
const WeightSchema = z.number().min(0).max(2);
// const IntegerSchema = z.number().int(); // Reserved for future use
const PositiveIntegerSchema = z.number().int().min(1);

// Tuning parameter schemas for individual stages
const HardAssertionTuningSchema = z.object({
  highConfidenceFloor: ProbabilitySchema.default(0.9),
  domainConfidenceBoost: z.number().min(0).max(0.2).default(0.1),
  subjectPrefixBoost: z.number().min(0).max(0.15).default(0.1),
  fromAddressBoost: z.number().min(0).max(0.1).default(0.05),
  parallelProcessingEnabled: z.boolean().default(true),
});

const StrongIndicatorTuningSchema = z.object({
  baseSeedValue: ProbabilitySchema.default(0.6),
  diminishingReturns: z.object({
    enabled: z.boolean().default(true),
    decayFactor: z.number().min(0.1).max(0.9).default(0.8),
    maxIndicators: PositiveIntegerSchema.default(5),
    minimumValueThreshold: z.number().min(0).max(0.1).default(0.05),
  }),
  domainWeightMultiplier: WeightSchema.default(1.2),
  contentWeightMultiplier: WeightSchema.default(1.0),
  parallelSeedingEnabled: z.boolean().default(true),
});

const RuleScoringTuningSchema = z.object({
  // Subtype scoring formula parameters (K_high, K_medium, K_low)
  K_high: PositiveNumberSchema.default(1.0),
  K_medium: PositiveNumberSchema.default(0.7),
  K_low: PositiveNumberSchema.default(0.3),

  // Bounded aggregation parameters
  aggregationCap: ProbabilitySchema.default(1.0),
  saturationThreshold: ProbabilitySchema.default(0.95),
  diminishingFactor: z.number().min(0.5).max(1.0).default(0.9),

  // Rule evaluation settings
